import base64, json, os
b64 = ""
msg = json.loads(base64.b64decode(b64).decode())
inbox = r"C:\Users\Administrator\.openclaw\workspace\arc-inbox"
os.makedirs(inbox, exist_ok=True)
path = os.path.join(inbox, "e5e33f76.json")
with open(path, "w", encoding="utf-8") as f:
    json.dump(msg, f, ensure_ascii=False, indent=2)
print(f"ARC message delivered!")
print(f"MsgID: e5e33f76")
print(f"Type: game_invite")
